sp_widget.client_script:
api.controller=function() {
  var c = this;
  c.inputValue = '';
  c.submitterDisplay = c.data.submitterDisplay;
  c.isSubmitting = false;
  c.error = '';

  c.submit = function() {
    c.isSubmitting = true;
    c.error = '';
    c.server.update({ user_input: c.inputValue }).then(function(response) {
      if (response && response.success) {
        window.location.href = '/sp?id=promptception_list';
      } else {
        c.error = response.error || 'Submission failed.';
      }
      c.isSubmitting = false;
    });
  };
};

sp_widget.css:
.prompt-input-form {
  max-width: 500px;
  margin: 30px auto;
  padding: 20px;
  border: 1px solid #ddd;
  border-radius: 4px;
  background: #fff;
}
.prompt-input-form label {
  font-weight: bold;
}
.prompt-input-form .form-group {
  margin-bottom: 15px;
}
.prompt-input-form .readonly-field {
  background: #f5f5f5;
  border: 1px solid #e0e0e0;
  padding: 8px 12px;
  border-radius: 4px;
}
.prompt-input-form .btn {
  min-width: 120px;
}
.prompt-input-form .error {
  color: #c0392b;
  margin-top: 10px;
}

sp_widget.script:
(function() {
  // Get the logged-in user's display name and sys_id
  var user = gs.getUser();
  data.submitterDisplay = user.getDisplayName();
  data.submitterSysId = user.getID();

  // Handle form submission from client
  if (input && input.user_input) {
    try {
      var gr = new GlideRecord('x_snc_ehd_promptce_prompt');
      gr.initialize();
      gr.user_input = input.user_input;
      gr.submitter = data.submitterSysId;
      gr.display_on_portal = true;
      gr.state = 'new';
      gr.insert();
      data.success = true;
    } catch (e) {
      data.success = false;
      data.error = e.message || 'Failed to create record.';
    }
  }
})();
